  arch_diag_r: ["\u2572", "\\", "\u2572", "\\", "\u2572", "\\", "\u2572", "\\"],
  // Broken seam characters for emergency exits
  seam_broken: ["\u254F", "\u2506", "\u250A", "\u254E", "\u2502", "\u2507", "\u2506", "\u254F"],
